app.post('/login', (req, res) => {
    const { username, password } = req.body;
    const user = findUser(username, password);

    if (user) {
        req.session.userId = user.id;
        const oauthParams = req.session.oauthParams;
        delete req.session.oauthParams; // Clear stored parameters

        if (oauthParams) {
            // Redirect back to /authorize with original parameters
            const authorizeUrl = new URL(`http://localhost:${PORT}/authorize`);
            for (const key in oauthParams) {
                authorizeUrl.searchParams.append(key, oauthParams[key]);
            }
            return res.redirect(authorizeUrl.toString());
        } else {
            // If no oauthParams, just logged in, redirect to a generic success page or home
            return res.send('Successfully logged in! No pending OAuth authorization request.');
        }
    } else {
        return res.redirect('/login?error=Invalid username or password.');
    }
});

// 3. Token Endpoint
// Exchanges an authorization code for an access token
app.post('/token', (req, res) => {
    const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

    // Validate grant_type
    if (grant_type !== 'authorization_code') {
        return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Grant type must be "authorization_code".' });
    }
    // Validate required parameters
    if (!code || !client_id || !client_secret || !redirect_uri) {
        return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters.' });
    }

    // Validate client credentials
    const client = findClientById(client_id);
    if (!client || client.clientSecret !== client_secret) {
        return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client_id or client_secret.' });
    }
    // Validate redirect_uri (must match the one used during authorization)
    if (!client.redirectUris.includes(redirect_uri)) {
        return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid redirect_uri.' });
    }

    // Validate authorization code
    const authCode = authorizationCodes[code];
    if (!authCode) {
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid or expired authorization code.' });
    }
    // Ensure code belongs to the requesting client and matches redirect_uri
    if (authCode.clientId !== client_id || authCode.redirectUri !== redirect_uri) {
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code does not match client_id or redirect_uri.' });
    }
    // Check if code has expired
    if (Date.now() > authCode.expiresAt) {
        delete authorizationCodes[code]; // Clean up expired code
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code has expired.' });
    }

    // Invalidate the authorization code after successful use (OAuth 2.0 codes are single-use)
    delete authorizationCodes[code];

    // Generate access token
    const accessToken = generateRandomString(64);
    const accessTokenExpiresAt = Date.now() + TOKEN_EXPIRY_SECONDS * 1000;

    accessTokens[accessToken] = {
        clientId: authCode.clientId,
        userId: authCode.userId,
        scope: authCode.scope,
        expiresAt: accessTokenExpiresAt
    };

    // Respond with the access token
    res.json({
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: TOKEN_EXPIRY_SECONDS,
        // refresh_token: generateRandomString(64) // Optional: Implement for long-lived access
    });
});

